var import_obsidian19 = require("obsidian");
var TagTemplateEditModal = class extends import_obsidian19.Modal {
  t;
  template;
  tagFormat;
  existingNames;
  onSave;
  nameInput = "";
  tagsInput = "";
  constructor(app, t, tagFormat, existingNames, template, onSave) {
    super(app);
    this.t = t;
    this.tagFormat = tagFormat;
    this.existingNames = existingNames;
    this.template = template;
    this.onSave = onSave;
    if (template) {
      this.nameInput = template.name;
      this.tagsInput = template.tags.join(", ");
    }
  }
  onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.addClass("tag-template-edit-modal");
    contentEl.createEl("h3", {
      text: this.template ? this.t.tagTemplates.editTemplate : this.t.tagTemplates.addTemplate
    });
    new import_obsidian19.Setting(contentEl).setName(this.t.tagTemplates.templateName).addText((text) => {
      text.setPlaceholder(this.t.tagTemplates.templateNamePlaceholder).setValue(this.nameInput).onChange((value) => this.nameInput = value);
      text.inputEl.style.width = "300px";
    });
    new import_obsidian19.Setting(contentEl).setName(this.t.tagTemplates.templateTags).setDesc(this.t.tagTemplates.templateTagsDesc).addTextArea((text) => {
      text.setPlaceholder(this.t.tagTemplates.templateTagsPlaceholder).setValue(this.tagsInput).onChange((value) => this.tagsInput = value);
      text.inputEl.style.width = "300px";
      text.inputEl.style.height = "80px";
    });
    const buttonContainer = contentEl.createDiv({ cls: "tag-template-buttons" });
    buttonContainer.createEl("button", { text: this.t.tagTemplates.cancel }).addEventListener("click", () => this.close());
    const saveBtn = buttonContainer.createEl("button", {
      text: this.t.tagTemplates.save,
      cls: "mod-cta"
    });
    saveBtn.addEventListener("click", () => this.handleSave());
  }
  handleSave() {
    const name = this.nameInput.trim();
    if (!name) {
      new import_obsidian19.Notice(this.t.tagTemplates.emptyName);
      return;
    }
    const isDuplicate = this.existingNames.some(
      (n) => n.toLowerCase() === name.toLowerCase() && (!this.template || n.toLowerCase() !== this.template.name.toLowerCase())
    );
    if (isDuplicate) {
      new import_obsidian19.Notice(this.t.tagTemplates.duplicateName);
      return;
    }
    const rawTags = this.tagsInput.split(",").map((t) => t.trim()).filter((t) => t);
    if (rawTags.length === 0) {
      new import_obsidian19.Notice(this.t.tagTemplates.emptyTags);
      return;
    }
    const tags = TagUtils.formatTags(rawTags, false, this.tagFormat);
    const template = {
      id: this.template?.id || crypto.randomUUID(),
      name,
      tags
    };
    this.onSave(template);
    this.close();
  }
  onClose() {
    this.contentEl.empty();
  }
};

// src/ui/settings/TagTemplatesSection.ts
var TagTemplatesSection = class extends BaseSettingSection {
  display() {
    this.containerEl.createEl("h1", { text: this.plugin.t.tagTemplates.title });
    this.containerEl.createEl("p", {
      text: this.plugin.t.tagTemplates.description,
      cls: "setting-item-description"
    });
    new import_obsidian20.Setting(this.containerEl).addButton((btn) => {
      btn.setButtonText(this.plugin.t.tagTemplates.addTemplate).setCta().onClick(() => this.openEditModal(null));
    });
    const listEl = this.containerEl.createDiv({ cls: "tag-templates-list" });
    this.renderTemplatesList(listEl);
  }
  renderTemplatesList(listEl) {
    listEl.empty();
    const templates = this.plugin.settings.tagTemplates;
    if (templates.length === 0) {
      listEl.createEl("p", {
        text: this.plugin.t.tagTemplates.noTemplates,
        cls: "tag-templates-empty"
      });
      return;
    }
    for (const template of templates) {
      const itemEl = listEl.createDiv({ cls: "tag-template-setting-item" });
      const infoEl = itemEl.createDiv({ cls: "tag-template-info" });
      infoEl.createDiv({ cls: "tag-template-name", text: template.name });
      infoEl.createDiv({
        cls: "tag-template-tags",
        text: template.tags.map((t) => `#${t}`).join(" ")
      });
      const actionsEl = itemEl.createDiv({ cls: "tag-template-actions" });
      const editBtn = actionsEl.createEl("button", {
        text: this.plugin.t.tagTemplates.editTemplate,
        cls: "tag-template-btn"
      });
      editBtn.addEventListener("click", () => this.openEditModal(template));
      const deleteBtn = actionsEl.createEl("button", {
        text: this.plugin.t.tagTemplates.deleteTemplate,
        cls: "tag-template-btn mod-warning"
      });
      deleteBtn.addEventListener("click", () => this.deleteTemplate(template, listEl));
    }
  }
  openEditModal(template) {
    const existingNames = this.plugin.settings.tagTemplates.map((t) => t.name);
    new TagTemplateEditModal(
      this.plugin.app,
      this.plugin.t,
      this.plugin.settings.tagFormat,
      existingNames,
      template,
      async (savedTemplate) => {
        const templates = this.plugin.settings.tagTemplates;
        const existingIndex = templates.findIndex((t) => t.id === savedTemplate.id);
        if (existingIndex >= 0) {
          templates[existingIndex] = savedTemplate;
        } else {
          templates.push(savedTemplate);
        }
        await this.plugin.saveSettings();
        const listEl = this.containerEl.querySelector(".tag-templates-list");
        if (listEl) {
          this.renderTemplatesList(listEl);
        }
      }
    ).open();
  }
  async deleteTemplate(template, listEl) {
    const confirmMsg = this.plugin.t.tagTemplates.deleteConfirm.replace("{name}", template.name);
    const confirmed = await this.plugin.showConfirmationDialog(confirmMsg);
    if (!confirmed)
      return;
    this.plugin.settings.tagTemplates = this.plugin.settings.tagTemplates.filter(
      (t) => t.id !== template.id
    );
    await this.plugin.saveSettings();
    this.renderTemplatesList(listEl);
  }
};

